final:
module shift_register(
    input clk,
    input load,
    input [3:0] d,
    input s_in,

    output [3:0] q
);

reg [3:0] q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
begin
  if (load)
    q <= d;
  else
    q <= {s_in, q[3:1]};
end

endmodule
